import React, { useState } from "react";

export default function SignInScreen({ onSignIn }) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const handleSignIn = () => {
    if (!email || !password) return alert("Enter email and password");
    onSignIn({ email, password });
  };

  return (
    <div className="w-screen h-screen flex flex-col justify-center px-6 bg-gray-50">
      <h1 className="text-3xl font-bold mb-8 text-center">Sign In</h1>
      <input
        type="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        className="w-full p-3 mb-4 rounded-xl border"
      />
      <input
        type="password"
        placeholder="Password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        className="w-full p-3 mb-6 rounded-xl border"
      />
      <button
        onClick={handleSignIn}
        className="w-full py-3 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700 transition-colors"
      >
        Sign In
      </button>
      <p className="mt-4 text-center text-gray-500 text-sm">
        Don't have an account? <span className="text-teal-600 cursor-pointer" onClick={() => alert("Go to Sign Up")}>Sign Up</span>
      </p>
    </div>
  );
}
